import { useState, useRef, useCallback, useEffect } from 'react';
import { useHaptic } from '@/hooks/useHaptic';

const THRESHOLD = 80;
const MAX_PULL = 120;

export function usePullToRefresh(onRefresh) {
  const [pullDistance, setPullDistance] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const startY = useRef(null);
  const rafRef = useRef(null);
  const containerRef = useRef(null);
  const haptic = useHaptic();

  const getScrollTop = useCallback(() => {
    const el = containerRef.current;
    if (el) return el.scrollTop;
    return window.scrollY || document.documentElement.scrollTop;
  }, []);

  const animateTo = useCallback((from, to, duration = 250) => {
    const start = performance.now();
    const tick = (now) => {
      const t = Math.min((now - start) / duration, 1);
      const ease = 1 - Math.pow(1 - t, 3);
      setPullDistance(from + (to - from) * ease);
      if (t < 1) rafRef.current = requestAnimationFrame(tick);
    };
    rafRef.current = requestAnimationFrame(tick);
  }, []);

  const onTouchStart = useCallback((e) => {
    if (isRefreshing) return;
    if (getScrollTop() !== 0) return;
    startY.current = e.touches[0].clientY;
  }, [isRefreshing, getScrollTop]);

  const onTouchMove = useCallback((e) => {
    if (startY.current === null || isRefreshing) return;
    const dy = e.touches[0].clientY - startY.current;
    if (dy <= 0) { startY.current = null; return; }
    if (getScrollTop() !== 0) { startY.current = null; return; }

    // Rubber-band resistance: pull slows down as it nears MAX_PULL
    const resistance = 1 - dy / (MAX_PULL * 2.5);
    const dist = Math.min(dy * Math.max(resistance, 0.2), MAX_PULL);

    if (rafRef.current) cancelAnimationFrame(rafRef.current);
    rafRef.current = requestAnimationFrame(() => setPullDistance(dist));

    if (dy > 10) e.preventDefault();
  }, [isRefreshing, getScrollTop]);

  const onTouchEnd = useCallback(() => {
    if (startY.current === null) return;
    startY.current = null;

    if (pullDistance >= THRESHOLD) {
      haptic.medium();
      setPullDistance(THRESHOLD);
      setIsRefreshing(true);
      Promise.resolve(onRefresh?.()).finally(() => {
        haptic.success();
        animateTo(THRESHOLD, 0);
        setIsRefreshing(false);
      });
    } else {
      animateTo(pullDistance, 0);
    }
  }, [pullDistance, onRefresh, animateTo]);

  useEffect(() => {
    const el = containerRef.current || window;
    const opts = { passive: false };
    el.addEventListener('touchstart', onTouchStart, opts);
    el.addEventListener('touchmove', onTouchMove, opts);
    el.addEventListener('touchend', onTouchEnd);
    return () => {
      el.removeEventListener('touchstart', onTouchStart);
      el.removeEventListener('touchmove', onTouchMove);
      el.removeEventListener('touchend', onTouchEnd);
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [onTouchStart, onTouchMove, onTouchEnd]);

  const progress = Math.min(pullDistance / THRESHOLD, 1);

  function PullIndicator() {
    if (pullDistance === 0 && !isRefreshing) return null;
    return (
      <div style={{
        position: 'absolute', top: 0, left: 0, right: 0, zIndex: 50,
        display: 'flex', justifyContent: 'center', alignItems: 'center',
        height: `${isRefreshing ? THRESHOLD : pullDistance}px`,
        overflow: 'hidden', transition: isRefreshing ? 'height 0.2s ease' : 'none',
        pointerEvents: 'none',
      }}>
        <div style={{
          width: 32, height: 32, borderRadius: '50%',
          border: '3px solid #d1fae5',
          borderTopColor: '#10b981',
          opacity: isRefreshing ? 1 : progress,
          transform: isRefreshing
            ? 'none'
            : `rotate(${progress * 270}deg) scale(${0.6 + progress * 0.4})`,
          animation: isRefreshing ? 'ptr-spin 0.7s linear infinite' : 'none',
        }} />
        <style>{`@keyframes ptr-spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  return { isRefreshing, pullDistance, PullIndicator, containerRef };
}
